import keyword
import re

STDLIB_MODULES = {
    'abc', 'argparse', 'ast', 'asyncio', 'base64', 'bisect',
    'collections', 'contextlib', 'copy', 'csv', 'dataclasses',
    'datetime', 'decimal', 'enum', 'functools', 'glob', 'hashlib',
    'heapq', 'http', 'io', 'itertools', 'json', 'keyword',
    'logging', 'math', 'operator', 'os', 'pathlib', 'pickle',
    'pprint', 're', 'random', 'shutil', 'socket', 'sqlite3',
    'string', 'struct', 'subprocess', 'sys', 'tempfile', 'threading',
    'time', 'typing', 'unittest', 'urllib', 'uuid', 'warnings',
    'xml', 'zipfile'
}


def sort_imports(import_lines):
    stdlib = []
    third_party = []
    local = []

    for line in import_lines:
        stripped = line.strip()
        if not stripped:
            continue
        if stripped.startswith('from .') or stripped.startswith('from ..'):
            local.append(stripped)
        else:
            if stripped.startswith('import '):
                module = stripped.split()[1].split('.')[0]
            elif stripped.startswith('from '):
                module = stripped.split()[1].split('.')[0]
            else:
                module = ''

            if module in STDLIB_MODULES:
                stdlib.append(stripped)
            else:
                third_party.append(stripped)

    result = []
    if stdlib:
        result.extend(sorted(stdlib))
    if third_party:
        if result:
            result.append('')
        result.extend(sorted(third_party))
    if local:
        if result:
            result.append('')
        result.extend(sorted(local))

    return result


def extract_public_api(source_lines):
    public = []
    for line in source_lines:
        stripped = line.strip()
        if stripped.startswith('def ') or stripped.startswith('class '):
            rest = stripped.split(None, 1)[1]
            name = rest.split('(')[0].split(':')[0].strip()
            if not name.startswith('_'):
                public.append(name)
    return public


def validate_module_name(name):
    if not name:
        return False
    if keyword.iskeyword(name):
        return False
    return bool(re.match(r'^[a-z][a-z0-9_]*$', name))


def create_init_content(module_names):
    sorted_names = sorted(module_names)
    all_items = ', '.join(repr(n) for n in sorted_names)
    header = '__all__ = [' + all_items + ']'
    imports = []
    for name in sorted_names:
        imports.append('from .' + name + ' import *')
    return header + '\n\n' + '\n'.join(imports)
